+    }
+
+    fn valid_override() -> PolicyOverride {
+        PolicyOverride {
+            override_id: "OVERRIDE-TEST-001".to_string(),
+            connector_id: "test-conn".to_string(),
+            reason: "Testing override".to_string(),
