+        assert_eq!(report.passed, 2);
+        assert_eq!(report.blocked, 0);
+    }
+
+    #[test]
+    fn harness_mixed_results() {
+        let connectors = vec![
+            ("conn-ok".to_string(), full_declarations(), None),
