+//! bd-bq6y: Generic lease service for operation execution, state writes,
+//! and migration handoff.
+//!
+//! Leases have deterministic expiry and renewal. Stale lease usage is rejected.
+
+use std::collections::HashMap;
+
+/// Purpose for which a lease is held.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
+pub enum LeasePurpose {
+    Operation,
+    StateWrite,
+    MigrationHandoff,
+}
+
+impl std::fmt::Display for LeasePurpose {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        match self {
+            Self::Operation => write!(f, "Operation"),
+            Self::StateWrite => write!(f, "StateWrite"),
+            Self::MigrationHandoff => write!(f, "MigrationHandoff"),
+        }
+    }
+}
+
+/// A lease granting time-limited access for a specific purpose.
+#[derive(Debug, Clone)]
+pub struct Lease {
+    pub lease_id: String,
+    pub holder: String,
+    pub purpose: LeasePurpose,
+    pub ttl_secs: u64,
+    pub granted_at: u64,
+    pub renewed_at: u64,
+    pub revoked: bool,
+}
+
+impl Lease {
+    /// Check if the lease is expired at time `now`.
+    pub fn is_expired(&self, now: u64) -> bool {
+        now > self.renewed_at + self.ttl_secs
+    }
+
+    /// Check if the lease is active (not expired and not revoked).
+    pub fn is_active(&self, now: u64) -> bool {
+        !self.revoked && !self.is_expired(now)
+    }
+
+    /// Remaining seconds until expiry (0 if already expired).
+    pub fn remaining(&self, now: u64) -> u64 {
+        let expires_at = self.renewed_at + self.ttl_secs;
+        expires_at.saturating_sub(now)
+    }
+}
+
+/// Audit record for lease operations.
+#[derive(Debug, Clone)]
+pub struct LeaseDecision {
+    pub lease_id: String,
+    pub action: String,
+    pub allowed: bool,
+    pub reason: String,
+    pub trace_id: String,
+    pub timestamp: String,
+}
+
+/// Errors from lease operations.
+///
+/// Error codes: `LS_EXPIRED`, `LS_STALE_USE`, `LS_ALREADY_REVOKED`, `LS_PURPOSE_MISMATCH`.
+#[derive(Debug, Clone, PartialEq, Eq)]
+pub enum LeaseError {
+    Expired { lease_id: String },
+    StaleUse { lease_id: String },
+    AlreadyRevoked { lease_id: String },
+    PurposeMismatch { lease_id: String, expected: String, actual: String },
+}
+
+impl LeaseError {
+    pub fn code(&self) -> &'static str {
+        match self {
+            Self::Expired { .. } => "LS_EXPIRED",
+            Self::StaleUse { .. } => "LS_STALE_USE",
+            Self::AlreadyRevoked { .. } => "LS_ALREADY_REVOKED",
+            Self::PurposeMismatch { .. } => "LS_PURPOSE_MISMATCH",
+        }
+    }
+}
+
+impl std::fmt::Display for LeaseError {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        match self {
+            Self::Expired { lease_id } => write!(f, "LS_EXPIRED: {lease_id}"),
+            Self::StaleUse { lease_id } => write!(f, "LS_STALE_USE: {lease_id}"),
+            Self::AlreadyRevoked { lease_id } => write!(f, "LS_ALREADY_REVOKED: {lease_id}"),
+            Self::PurposeMismatch { lease_id, expected, actual } => {
+                write!(f, "LS_PURPOSE_MISMATCH: {lease_id} expected {expected}, got {actual}")
+            }
+        }
+    }
+}
+
+/// Generic lease service.
+pub struct LeaseService {
+    leases: HashMap<String, Lease>,
+    pub decisions: Vec<LeaseDecision>,
+    next_id: u64,
+}
+
+impl LeaseService {
+    pub fn new() -> Self {
+        Self {
+            leases: HashMap::new(),
+            decisions: Vec::new(),
+            next_id: 1,
+        }
+    }
+
+    /// Grant a new lease.
+    pub fn grant(
+        &mut self,
+        holder: &str,
+        purpose: LeasePurpose,
+        ttl_secs: u64,
+        now: u64,
+        trace_id: &str,
+        timestamp: &str,
+    ) -> Lease {
+        let lease_id = format!("lease-{}", self.next_id);
+        self.next_id += 1;
+
+        let lease = Lease {
+            lease_id: lease_id.clone(),
+            holder: holder.to_string(),
+            purpose,
+            ttl_secs,
+            granted_at: now,
+            renewed_at: now,
+            revoked: false,
+        };
+
+        self.leases.insert(lease_id.clone(), lease.clone());
+        self.decisions.push(LeaseDecision {
+            lease_id: lease_id.clone(),
+            action: "grant".into(),
+            allowed: true,
+            reason: format!("granted {purpose} lease to {holder}"),
+            trace_id: trace_id.to_string(),
+            timestamp: timestamp.to_string(),
+        });
+
+        lease
+    }
+
+    /// Renew a lease, extending its TTL from `now`.
+    ///
+    /// INV-LS-RENEWAL: only active leases can be renewed.
+    pub fn renew(
+        &mut self,
+        lease_id: &str,
+        now: u64,
+        trace_id: &str,
+        timestamp: &str,
+    ) -> Result<Lease, LeaseError> {
+        let lease = self.leases.get(lease_id).ok_or_else(|| LeaseError::Expired {
+            lease_id: lease_id.to_string(),
+        })?;
+
+        if lease.revoked {
+            self.decisions.push(LeaseDecision {
+                lease_id: lease_id.to_string(),
+                action: "renew".into(),
+                allowed: false,
+                reason: "lease revoked".into(),
+                trace_id: trace_id.to_string(),
+                timestamp: timestamp.to_string(),
+            });
+            return Err(LeaseError::AlreadyRevoked { lease_id: lease_id.to_string() });
+        }
+
+        if lease.is_expired(now) {
+            self.decisions.push(LeaseDecision {
+                lease_id: lease_id.to_string(),
+                action: "renew".into(),
+                allowed: false,
+                reason: "lease expired".into(),
+                trace_id: trace_id.to_string(),
+                timestamp: timestamp.to_string(),
+            });
+            return Err(LeaseError::Expired { lease_id: lease_id.to_string() });
+        }
+
+        let lease = self.leases.get_mut(lease_id).unwrap();
+        lease.renewed_at = now;
+
+        self.decisions.push(LeaseDecision {
+            lease_id: lease_id.to_string(),
+            action: "renew".into(),
+            allowed: true,
+            reason: "renewed".into(),
+            trace_id: trace_id.to_string(),
+            timestamp: timestamp.to_string(),
+        });
+
+        Ok(lease.clone())
+    }
+
+    /// Use a lease for an operation. Validates active + correct purpose.
+    ///
+    /// INV-LS-STALE-REJECT: expired/revoked leases rejected.
+    /// INV-LS-PURPOSE: purpose must match.
+    pub fn use_lease(
+        &mut self,
+        lease_id: &str,
+        required_purpose: LeasePurpose,
+        now: u64,
+        trace_id: &str,
+        timestamp: &str,
+    ) -> Result<LeaseDecision, LeaseError> {
+        let lease = self.leases.get(lease_id).ok_or_else(|| LeaseError::StaleUse {
+            lease_id: lease_id.to_string(),
+        })?;
+
+        if lease.revoked {
+            let d = LeaseDecision {
+                lease_id: lease_id.to_string(),
+                action: "use".into(),
+                allowed: false,
+                reason: "lease revoked".into(),
+                trace_id: trace_id.to_string(),
+                timestamp: timestamp.to_string(),
+            };
+            self.decisions.push(d.clone());
+            return Err(LeaseError::StaleUse { lease_id: lease_id.to_string() });
+        }
+
+        if lease.is_expired(now) {
+            let d = LeaseDecision {
+                lease_id: lease_id.to_string(),
+                action: "use".into(),
+                allowed: false,
+                reason: "lease expired".into(),
+                trace_id: trace_id.to_string(),
+                timestamp: timestamp.to_string(),
+            };
+            self.decisions.push(d.clone());
+            return Err(LeaseError::StaleUse { lease_id: lease_id.to_string() });
+        }
+
+        // INV-LS-PURPOSE
+        if lease.purpose != required_purpose {
+            let d = LeaseDecision {
+                lease_id: lease_id.to_string(),
+                action: "use".into(),
+                allowed: false,
+                reason: format!("purpose mismatch: expected {required_purpose}, got {}", lease.purpose),
+                trace_id: trace_id.to_string(),
+                timestamp: timestamp.to_string(),
+            };
+            self.decisions.push(d.clone());
+            return Err(LeaseError::PurposeMismatch {
+                lease_id: lease_id.to_string(),
+                expected: required_purpose.to_string(),
+                actual: lease.purpose.to_string(),
+            });
+        }
+
+        let d = LeaseDecision {
+            lease_id: lease_id.to_string(),
+            action: "use".into(),
+            allowed: true,
+            reason: "lease valid".into(),
+            trace_id: trace_id.to_string(),
+            timestamp: timestamp.to_string(),
+        };
+        self.decisions.push(d.clone());
+        Ok(d)
+    }
+
+    /// Revoke a lease.
+    pub fn revoke(
+        &mut self,
+        lease_id: &str,
+        trace_id: &str,
+        timestamp: &str,
+    ) -> Result<(), LeaseError> {
+        let lease = self.leases.get_mut(lease_id).ok_or_else(|| LeaseError::Expired {
+            lease_id: lease_id.to_string(),
+        })?;
+
+        if lease.revoked {
+            return Err(LeaseError::AlreadyRevoked { lease_id: lease_id.to_string() });
+        }
+
+        lease.revoked = true;
+        self.decisions.push(LeaseDecision {
+            lease_id: lease_id.to_string(),
+            action: "revoke".into(),
+            allowed: true,
+            reason: "revoked".into(),
+            trace_id: trace_id.to_string(),
+            timestamp: timestamp.to_string(),
+        });
+
+        Ok(())
+    }
+
+    /// Get a lease by ID (read-only).
+    pub fn get(&self, lease_id: &str) -> Option<&Lease> {
+        self.leases.get(lease_id)
+    }
+
+    /// Total active leases at time `now`.
+    pub fn active_count(&self, now: u64) -> usize {
+        self.leases.values().filter(|l| l.is_active(now)).count()
+    }
+}
+
