+
+    #[test]
+    fn semver_ordering() {
+        assert!(SemVer::new(2, 0, 0) > SemVer::new(1, 99, 99));
+        assert!(SemVer::new(1, 1, 0) > SemVer::new(1, 0, 99));
+        assert!(SemVer::new(1, 0, 1) > SemVer::new(1, 0, 0));
+        assert!(SemVer::new(1, 0, 0) == SemVer::new(1, 0, 0));
+    }
+
+    #[test]
