+        let h = compute_hash("conn.v1", b"data");
+        assert!(tel.admit("c1", &h, "conn.v1", b"data", "t1", "ts"));
+        assert!(!tel.admit("c2", &h, "conn.v1", b"bad", "t2", "ts"));
