+    }
+
+    // === Serde ===
+
+    #[test]
+    fn serde_roundtrip_interface_hash() {
+        let h = compute_hash("test.v1", b"sample");
+        let json = serde_json::to_string(&h).unwrap();
+        let parsed: InterfaceHash = serde_json::from_str(&json).unwrap();
+        assert_eq!(h, parsed);
+    }
+
+    #[test]
